using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record PredictRequest(string Subject, string Description, int Priority);

public record PredictResponse(string Category, Dictionary<string, float> Confidence);

public record EvaluationResponse(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    Dictionary<string, PerClassMetrics> PerClassMetrics);

public record PerClassMetrics(double Precision, double Recall);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryLabels = [];

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void Train()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Cache the ordered label names so we can map Score[] to categories
        var labelColumn = dataView.Schema["Category"];
        var keyColumn = _model.GetOutputSchema(dataView.Schema)["Label"];
        var keyType = keyColumn.Type as Microsoft.ML.Data.KeyDataViewType;

        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        _model.GetOutputSchema(dataView.Schema)["Label"]
              .GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
    }

    public EvaluationResponse Evaluate()
    {
        if (_model is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var perClass = new Dictionary<string, Models.PerClassMetrics>();
        for (var i = 0; i < metrics.PerClassLogLoss.Count && i < _categoryLabels.Length; i++)
        {
            perClass[_categoryLabels[i]] = new Models.PerClassMetrics(
                Precision: metrics.ConfusionMatrix.PerClassPrecision[i],
                Recall: metrics.ConfusionMatrix.PerClassRecall[i]);
        }

        return new EvaluationResponse(
            MacroAccuracy: metrics.MacroAccuracy,
            MicroAccuracy: metrics.MicroAccuracy,
            LogLoss: metrics.LogLoss,
            LogLossReduction: metrics.LogLossReduction,
            PerClassMetrics: perClass);
    }

    public PredictResponse Predict(PredictRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var ticket = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticket);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictResponse(prediction.Category, confidence);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketClassifierService service) : ControllerBase
{
    [HttpPost("train")]
    public IActionResult Train()
    {
        service.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        if (!service.IsModelTrained)
            return BadRequest(new { error = "Model has not been trained yet. POST /api/ticketclassifier/train first." });

        return Ok(service.Evaluate());
    }

    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (!service.IsModelTrained)
            return BadRequest(new { error = "Model has not been trained yet. POST /api/ticketclassifier/train first." });

        if (request.Priority is < 1 or > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        return Ok(service.Predict(request));
    }
}

